functions.color-function:
main: (i) => {
	function color(i) {
		let c = 255	
		if (i == -1) return colorHelper(255, 255, 255)
		if (i == 0) 
			c = 0
		return colorHelper(c, c, c)
	}
	function colorHelper(r, g, b) {
		return b + g * 0x100 + r* 0x10000
	}
	return color(i)
}

functions.pixel-function:
main: (x, y, z) => { 
	function calc(x, y, z) {
		if ((x < z && y < z)) 
			return (x * y) % z 
		else return -1

	} 
 return calc(x, y, z) 
}
